/**
 * Calculates the Greatest Common Divisor (GCD) of two numbers using the Euclidean algorithm.
 * @param {number} a
 * @param {number} b
 * @returns {number} The GCD of a and b.
 */
const gcd = (a, b) => {
    while (b) {
        [a, b] = [b, a % b];
    }
    return Math.abs(a);
};

/**
